import React, { useState } from 'react';
import { Link } from 'react-router-dom';
import './Login.css';

function Login() {
  const [formData, setFormData] = useState({ email: '', password: '' });

  const handleChange = (e) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    console.log("Login Data:", formData);
    // येथे तुम्ही तुमची API Logic लिहू शकता
  };

  return (
    <div className="login-container">
      <div className="card shadow login-card">
        <h2 className="text-center fw-bold mb-4">Welcome Back</h2>
        <form onSubmit={handleSubmit}>
          <div className="mb-3">
            <label className="form-label">Email Address</label>
            <input 
              type="email" name="email" 
              className="form-control form-control-sm" 
              placeholder="Enter email"
              onChange={handleChange} required 
            />
          </div>
          <div className="mb-3">
            <label className="form-label">Password</label>
            <input 
              type="password" name="password" 
              className="form-control form-control-sm" 
              placeholder="Enter password"
              onChange={handleChange} required 
            />
          </div>
          <button type="submit" className="btn btn-primary w-100 btn-sm shadow-sm mt-2">Login</button>
        </form>
        <p className="text-center mt-3 small text-muted">
          Don't have an account? <Link to="/register" className="text-primary fw-bold">Register</Link>
        </p>
      </div>
    </div>
  );
}

export default Login;
